var items = $input.all();
var seen = new Set();
var cleaned = [];
for (var i = 0; i < items.length; i++) {
  var d = items[i].json;
  var title = (d.title || "").trim();
  var link = (d.link || "").trim();
  if (!title || !link || seen.has(link)) continue;
  seen.add(link);
  var desc = (d.contentSnippet || d.content || d.description || "").replace(/<[^>]*>/g, "").trim();
  if (desc.length > 250) desc = desc.substring(0, 250) + "...";
  var pubDate = d.isoDate || d.pubDate || "";
  var source = d.creator || "";
  if (!source) { try { source = new URL(link).hostname.replace("www.", ""); } catch(e) {} }
  cleaned.push({ title: title, link: link, description: desc, pubDate: pubDate, source: source });
}
cleaned.sort(function(a, b) { return new Date(b.pubDate || 0) - new Date(a.pubDate || 0); });
cleaned = cleaned.slice(0, 150);
var articleList = cleaned.map(function(a, idx) {
  return "[" + idx + "] " + JSON.stringify(a.title) + " (" + (a.source || "Unknown") + ", " + (a.pubDate ? a.pubDate.substring(0, 10) : "No date") + ")\n   " + (a.description || "No description");
}).join("\n\n");
return [{ json: { articleCount: cleaned.length, articleList: articleList, articlesJson: JSON.stringify(cleaned) } }];

var aiOutput = $input.first().json.output;
var allArticles = JSON.parse($("Clean and Prepare for AI").first().json.articlesJson);
var selected;
try {
  var jsonMatch = aiOutput.match(/\{[\s\S]*\}/);
  var parsed = JSON.parse(jsonMatch ? jsonMatch[0] : aiOutput);
  selected = parsed.selected || parsed.indices || [];
} catch (e) {
  var nums = aiOutput.match(/\d+/g);
  selected = nums ? nums.map(Number) : [];
}
var articles = selected.filter(function(i) { return i >= 0 && i < allArticles.length; }).slice(0, 30).map(function(i) { return allArticles[i]; });
var today = new Date().toLocaleDateString("en-US", { weekday: "long", year: "numeric", month: "long", day: "numeric" });
var h = "<!DOCTYPE html><html><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\"></head>";
h += "<body style=\"margin:0;padding:0;background:#f1f5f9;font-family:-apple-system,BlinkMacSystemFont,Segoe UI,Roboto,Helvetica Neue,Arial,sans-serif;\">";
h += "<table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#f1f5f9;padding:32px 0;\">";
h += "<tr><td align=\"center\">";
h += "<table width=\"640\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#fff;border-radius:16px;box-shadow:0 4px 24px rgba(0,0,0,0.06);overflow:hidden;max-width:640px;width:100%;\">";
h += "<tr><td style=\"background:linear-gradient(135deg,#6366f1 0%,#8b5cf6 50%,#a855f7 100%);padding:48px 32px;text-align:center;\">";
h += "<h1 style=\"margin:0;color:#fff;font-size:32px;font-weight:800;letter-spacing:-0.5px;\">&#128236; Tech Digest</h1>";
h += "<p style=\"margin:10px 0 0;color:rgba(255,255,255,0.85);font-size:15px;\">" + today + " &#183; " + articles.length + " curated articles</p>";
h += "</td></tr>";
h += "<tr><td style=\"padding:28px 32px 12px;\"><p style=\"margin:0;color:#475569;font-size:15px;line-height:1.6;text-align:center;\">Your AI-curated daily selection of the most interesting tech articles from across the web.</p></td></tr>";
for (var idx = 0; idx < articles.length; idx++) {
  var a = articles[idx];
  var desc = (a.description || "").substring(0, 200);
  var src = a.source ? " &#183; " + a.source : "";
  var dt = "";
  try { dt = a.pubDate ? new Date(a.pubDate).toLocaleDateString("en-US", { month: "short", day: "numeric" }) : ""; } catch(e) {}
  var num = idx + 1;
  h += "<tr><td style=\"padding:6px 32px;\">";
  h += "<table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#f8fafc;border-radius:12px;border:1px solid #e2e8f0;\">";
  h += "<tr><td style=\"padding:18px 20px;\">";
  h += "<table cellpadding=\"0\" cellspacing=\"0\"><tr>";
  h += "<td style=\"vertical-align:top;padding-right:14px;\"><span style=\"display:inline-block;width:28px;height:28px;border-radius:50%;background:#6366f1;color:#fff;font-size:12px;font-weight:700;line-height:28px;text-align:center;\">" + num + "</span></td>";
  h += "<td>";
  h += "<a href=\"" + a.link + "\" style=\"color:#1e293b;text-decoration:none;font-size:16px;font-weight:600;line-height:1.4;\">" + a.title + "</a>";
  if (desc) h += "<p style=\"margin:6px 0 0;color:#64748b;font-size:13px;line-height:1.5;\">" + desc + "</p>";
  h += "<p style=\"margin:8px 0 0;font-size:11px;color:#94a3b8;\">" + dt + src + "</p>";
  h += "</td></tr></table>";
  h += "</td></tr></table></td></tr>";
}
h += "<tr><td style=\"padding:28px 32px;text-align:center;border-top:1px solid #e2e8f0;\">";
h += "<p style=\"margin:0;color:#94a3b8;font-size:13px;\">Curated with &#10084;&#65039; by your n8n RSS Digest workflow</p>";
h += "<p style=\"margin:4px 0 0;color:#cbd5e1;font-size:11px;\">27 RSS sources &#183; AI-curated daily</p>";
h += "</td></tr></table></td></tr></table></body></html>";
return [{ json: { emailHtml: h, emailSubject: "Tech Digest - " + today, articleCount: articles.length } }];
